INSERT INTO cancer_types (id, lang, name, description, symptoms, treatments, image_url) VALUES
('1','mm','အဆုတ်ကင်ဆာ','အဆုတ်ကင်ဆာသည် အဆုတ်တွင်စတင်ဖြစ်ပွားသော ကင်ဆာအမျိုးအစားဖြစ်သည်။ သင်၏အဆုတ်များသည် ရင်ဘတ်ထဲတွင်ရှိသော လေရှူသွင်းချိန်တွင် အောက်ဆီဂျင်ကိုရယူပြီး လေရှူထုတ်ချိန်တွင် ကာဗွန်ဒိုင်အောက်ဆိုက်ကို ထုတ်လွှတ်ပေးသော ရေမြှုပ်ကဲ့သို့သော အင်္ဂါအစိတ်အပိုင်းနှစ်ခုဖြစ်သည်။ ၎င်းသည် ကမ္ဘာတစ်ဝှမ်းတွင် ကင်ဆာကြောင့်သေဆုံးမှု အများဆုံးဖြစ်သည်။','• မပျောက်နိုင်သော ချောင်းဆိုးခြင်း\n• သွေးပါသော ချောင်းဆိုးခြင်း\n• အသက်ရှူမဝခြင်း\n• ရင်ဘတ်အောင့်ခြင်း\n• အသံဝင်ခြင်း\n• အကြောင်းရင်းမရှိဘဲ ကိုယ်အလေးချိန်ကျဆင်းခြင်း\n• အရိုးများနာကျင်ခြင်း\n• ခေါင်းကိုက်ခြင်း','ကုသမှုများသည် ကွဲပြားနိုင်သော်လည်း ခွဲစိတ်ကုသခြင်း၊ ဓာတ်ကင်ခြင်း၊ ဆေးသွင်းကုသခြင်း၊ ပစ်မှတ်ထားကုသခြင်းနှင့် ခုခံအားကုထုံးများ ပါဝင်နိုင်သည်။','https://images.unsplash.com/photo-1559757175-5700dde675bc?auto=format&fit=crop&q=80&w=800'),
('2','mm','ရင်သားကင်ဆာ','ရင်သားကင်ဆာသည် ရင်သားဆဲလ်များတွင် ဖြစ်ပွားသော ကင်ဆာဖြစ်သည်။ အရေပြားကင်ဆာပြီးလျှင် အမျိုးသမီးများတွင် အဖြစ်အများဆုံး ကင်ဆာဖြစ်သည်။ အမျိုးသားများတွင်လည်း ဖြစ်ပွားနိုင်သော်လည်း အမျိုးသမီးများတွင် ပိုမိုအဖြစ်များသည်။','• ရင်သားတွင် အကျိတ် သို့မဟုတ် ထူထဲသောနေရာ ပေါ်လာခြင်း\n• ရင်သားအရွယ်အစား၊ ပုံသဏ္ဍာန် သို့မဟုတ် ပုံပန်းသဏ္ဍာန် ပြောင်းလဲလာခြင်း\n• ရင်သားအရေပြား ပြောင်းလဲခြင်း (ဥပမာ - ချိုင့်ဝင်ခြင်း)\n• နို့သီးခေါင်း ပြောင်းပြန်ဝင်သွားခြင်း\n• နို့သီးခေါင်း သို့မဟုတ် ရင်သားအရေပြား အဖတ်လန်ခြင်း','ခွဲစိတ်ခြင်း၊ ဓာတ်ကင်ခြင်း၊ ဆေးသွင်းခြင်း၊ ဟော်မုန်းကုထုံးနှင့် ပစ်မှတ်ထားကုထုံးများ။','https://images.unsplash.com/photo-1631217868264-e5b90bb7e133?auto=format&fit=crop&q=80&w=800'),
('3','mm','အူမကြီးကင်ဆာ','အူမကြီးကင်ဆာသည် အူမကြီးတွင် စတင်ဖြစ်ပွားသော ကင်ဆာဖြစ်သည်။ အူမကြီးသည် အစာခြေစနစ်၏ နောက်ဆုံးအပိုင်းဖြစ်သည်။ အသက်ကြီးပိုင်းများတွင် အဖြစ်များသော်လည်း မည်သည့်အရွယ်တွင်မဆို ဖြစ်နိုင်သည်။','• ဝမ်းသွားခြင်း အလေ့အထပြောင်းလဲခြင်း (ဝမ်းလျှောခြင်း၊ ဝမ်းချုပ်ခြင်း)\n• ဝမ်းတွင် သွေးပါခြင်း\n• ဗိုက်အောင့်ခြင်း၊ လေပွခြင်း\n• ဝမ်းမသွားချင်ဘဲ သွားချင်စိတ်ဖြစ်ခြင်း\n• အားနည်းခြင်း၊ မောပန်းခြင်း\n• ကိုယ်အလေးချိန်ကျခြင်း','ခွဲစိတ်ကုသခြင်းသည် အဖြစ်အများဆုံးဖြစ်သည်။ အခြားနည်းလမ်းများမှာ ဆေးသွင်းခြင်း၊ ဓာတ်ကင်ခြင်းနှင့် ပစ်မှတ်ထားကုသခြင်းတို့ဖြစ်သည်။','https://images.unsplash.com/photo-1579684385127-1ef15d508118?auto=format&fit=crop&q=80&w=800'),
('4','mm','ဆီးကျိတ်ကင်ဆာ','ဆီးကျိတ်ကင်ဆာသည် ဆီးကျိတ်တွင် ဖြစ်ပွားသည်။ ဆီးကျိတ်သည် အမျိုးသားများတွင်သာရှိပြီး သုတ်ရည်ထုတ်လွှတ်ရာတွင် ကူညီပေးသော သစ်ကြားသီးအရွယ် ဂလင်းတစ်ခုဖြစ်သည်။ အဖြစ်များဆုံး ကင်ဆာများတွင် တစ်ခုအပါအဝင်ဖြစ်သည်။','အစောပိုင်းအဆင့်တွင် လက္ခဏာမပြတတ်ပါ။ အဆင့်မြင့်လာပါက:\n• ဆီးသွားရခက်ခဲခြင်း\n• ဆီးပွန်အားနည်းခြင်း\n• ဆီး သို့မဟုတ် သုတ်ရည်ထဲတွင် သွေးပါခြင်း\n• အရိုးနာကျင်ခြင်း\n• ပန်းသေခြင်း','ခွဲစိတ်ခြင်း၊ ဓာတ်ကင်ခြင်း၊ ဟော်မုန်းကုထုံး၊ ဆေးသွင်းခြင်းနှင့် ခုခံအားကုထုံး။','https://plus.unsplash.com/premium_photo-1673953509975-576678fa6710?auto=format&fit=crop&q=80&w=800'),
('5','mm','သွေးကင်ဆာ','သွေးကင်ဆာသည် ခန္ဓာကိုယ်၏ သွေးဆဲလ်များဖြစ်ပေါ်စေသော တစ်ရှူးများ (ရိုးတွင်းခြင်ဆီအပါအဝင်) တွင်ဖြစ်ပွားသော ကင်ဆာဖြစ်သည်။ ကလေးများတွင် အဖြစ်များသည့် ပုံစံများရှိသလို လူကြီးများတွင် အဖြစ်များသည့် ပုံစံများလည်း ရှိသည်။','• ဖျားခြင်း သို့မဟုတ် ချမ်းတုန်ခြင်း\n• မောပန်းနွမ်းနယ်ခြင်း\n• မကြာခဏ ပိုးဝင်ခြင်း\n• ကိုယ်အလေးချိန် ကျဆင်းခြင်း\n• သွေးထွက်လွယ်ခြင်း သို့မဟုတ် အမဲစက်စွဲလွယ်ခြင်း\n• နှာခေါင်းသွေး ခဏခဏလျှံခြင်း','ဆေးသွင်းကုသခြင်း၊ ပစ်မှတ်ထားကုသခြင်း၊ ဓာတ်ကင်ခြင်း၊ ရိုးတွင်းခြင်ဆီ အစားထိုးကုသခြင်းနှင့် ခုခံအားကုထုံး။','https://images.unsplash.com/photo-1579154204601-01588f351e67?auto=format&fit=crop&q=80&w=800'),
('6','mm','အရေပြားကင်ဆာ (Melanoma)','Melanoma သည် အန္တရာယ်အရှိဆုံး အရေပြားကင်ဆာဖြစ်သည်။ အရေပြားအရောင်ခြယ်ဆဲလ်များ (melanocytes) တွင် ဖြစ်ပွားသည်။ နေရောင်ခြည်ထိတွေ့မှုများသော နေရာများတွင် အဖြစ်များသည်။','• မှဲ့အရွယ်အစား၊ ပုံသဏ္ဍာန် သို့မဟုတ် အရောင်ပြောင်းလဲခြင်း\n• ပုံမှန်မဟုတ်သော အရောင်စုံ အစက်အပြောက်များပေါ်လာခြင်း\n• ပုံသဏ္ဍာန်မမှန်သော မှဲ့များ\n• အနားသတ်မညီသော မှဲ့များ\n• ချက်ချင်းကြီးထွားလာသော အကျိတ်များ','ခွဲစိတ်ခြင်း၊ ခုခံအားကုထုံး၊ ပစ်မှတ်ထားကုထုံး၊ ဓာတ်ကင်ခြင်းနှင့် ဆေးသွင်းကုသခြင်း။','https://images.unsplash.com/photo-1581091226825-a6a2a5aee158?auto=format&fit=crop&q=80&w=800'),
('7','mm','အသည်းကင်ဆာ','အသည်းကင်ဆာသည် ဝမ်းဗိုက်၏ ညာဘက်အပေါ်ပိုင်းရှိ ကြီးမားသော အင်္ဂါတစ်ခုဖြစ်သည့် အသည်းတွင် စတင်ဖြစ်ပွားသည်။ အဖြစ်အများဆုံးပုံစံမှာ Hepatocellular carcinoma ဖြစ်သည်။','• ကိုယ်အလေးချိန်ကျခြင်း\n• အစားအသောက်ပျက်ခြင်း\n• ဗိုက်အောင့်ခြင်း\n• ပျို့အန်ခြင်း\n• အသားဝါခြင်း (မျက်လုံးနှင့် အရေပြား ဝါခြင်း)\n• ဝမ်းဗိုက်ရောင်ရမ်းခြင်း\n• ဝမ်းအရောင် ဖြူဖျော့ဖျော့ဖြစ်ခြင်း','ခွဲစိတ်ခြင်း၊ အသည်းအစားထိုးခြင်း၊ အပူပေးကုသခြင်း၊ ဓာတ်ကင်ခြင်း၊ ပစ်မှတ်ထားဆေးကုသခြင်းနှင့် ခုခံအားကုထုံး။','https://images.unsplash.com/photo-1559757175-5700dde675bc?auto=format&fit=crop&q=80&w=800'),
('8','mm','အစာအိမ်ကင်ဆာ','အစာအိမ်ကင်ဆာသည် အစာအိမ်တွင် ပုံမှန်မဟုတ်သော ဆဲလ်များကြီးထွားခြင်းဖြစ်သည်။ အစာအိမ်၏ မည်သည့်အစိတ်အပိုင်းတွင်မဆို ဖြစ်နိုင်သည်။','• အစာနင်ခြင်း\n• အစာစားပြီး ရင်ပြည့်ခြင်း\n• အနည်းငယ်စားရုံဖြင့် ဗိုက်ဝခြင်း\n• ရင်ပူခြင်း\n• အစာမကြေခြင်း\n• ပျို့အန်ခြင်း\n• ဗိုက်နာခြင်း\n• ကိုယ်အလေးချိန်ကျခြင်း','ခွဲစိတ်ခြင်း၊ ဆေးသွင်းကုသခြင်း၊ ဓာတ်ကင်ခြင်း၊ ပစ်မှတ်ထားကုထုံးနှင့် ခုခံအားကုထုံး။','https://images.unsplash.com/photo-1511174511562-5f7f18b874f8?auto=format&fit=crop&q=80&w=800'),
('9','mm','သားအိမ်ခေါင်းကင်ဆာ','သားအိမ်ခေါင်းကင်ဆာသည် သားအိမ်၏အောက်ပိုင်း မိန်းမကိုယ်နှင့်ဆက်သွယ်ထားသော နေရာတွင်ဖြစ်ပွားသည်။ HPV ဗိုင်းရပ်စ်ပိုးကြောင့် အဓိကဖြစ်ပွားသည်။','• လိင်ဆက်ဆံပြီးချိန် သို့မဟုတ် ရာသီလာချိန်မဟုတ်ဘဲ သွေးဆင်းခြင်း\n• အနံ့နံသော အရည်ဆင်းခြင်း\n• ဆီးစပ်ကိုက်ခဲခြင်း','ခွဲစိတ်ခြင်း၊ ဓာတ်ကင်ခြင်း၊ ဆေးသွင်းကုသခြင်းနှင့် ပစ်မှတ်ထားကုထုံး။','https://images.unsplash.com/photo-1579684385127-1ef15d508118?auto=format&fit=crop&q=80&w=800'),
('10','mm','ပါးစပ်ကင်ဆာ','ပါးစပ်ကင်ဆာသည် နှုတ်ခမ်း၊ သွားဖုံး၊ လျှာ၊ ပါးစောင်၊ အာခေါင်တို့တွင် ဖြစ်ပွားနိုင်သည်။','• မပျောက်နိုင်သော အနာများ\n• ပါးစပ်အတွင်း အဖြူကွက် သို့မဟုတ် အနီကွက်များပေါ်ခြင်း\n• သွားနဲ့ခြင်း\n• ပါးစပ်အတွင်း အဖုအကျိတ်များပေါ်ခြင်း\n• မျိုချရခက်ခဲခြင်း','ခွဲစိတ်ခြင်း၊ ဓာတ်ကင်ခြင်းနှင့် ဆေးသွင်းကုသခြင်း။','https://images.unsplash.com/photo-1559757175-5700dde675bc?auto=format&fit=crop&q=80&w=800'),
('11','mm','သားဥအိမ်ကင်ဆာ','သားဥအိမ်ကင်ဆာသည် သားဥအိမ်တွင် ဆဲလ်များ လျင်မြန်စွာပွားများပြီး ကျန်းမာသောတစ်ရှူးများကို ဖျက်ဆီးသောရောဂါဖြစ်သည်။','• ဗိုက်ပွခြင်း၊ ရောင်ရမ်းခြင်း\n• အစားစားသောက်ပြီး ချက်ချင်းဗိုက်ဝခြင်း\n• ကိုယ်အလေးချိန်ကျခြင်း\n• ဆီးစပ်ကိုက်ခြင်း\n• မောပန်းခြင်း','ခွဲစိတ်ခြင်းနှင့် ဆေးသွင်းကုသခြင်းသည် အဓိကကုထုံးများဖြစ်သည်။','https://images.unsplash.com/photo-1631217868264-e5b90bb7e133?auto=format&fit=crop&q=80&w=800'),
('12','mm','ပန်ကရိယကင်ဆာ','ပန်ကရိယကင်ဆာသည် အစာခြေအင်ဇိုင်းနှင့် ဟော်မုန်းများထုတ်ပေးသော ပန်ကရိယတွင် ဖြစ်ပွားသည်။','• ကျောဘက်သို့ ပြန့်သွားသော ဗိုက်နာခြင်း\n• အစားအသောက်ပျက်ခြင်း\n• အသားဝါခြင်း\n• ဆီးအရောင်ရင့်ခြင်း\n• ယားယံခြင်း','ခွဲစိတ်ခြင်း၊ ဆေးသွင်းကုသခြင်းနှင့် ဓာတ်ကင်ခြင်း။','https://images.unsplash.com/photo-1628771065518-0d82f1938462?auto=format&fit=crop&q=80&w=800'),
('13','mm','သိုင်းရွိုက်ကင်ဆာ (လည်ပင်းကြီးကင်ဆာ)','သိုင်းရွိုက်ကင်ဆာသည် လည်ပင်းအောက်ခြေရှိ လိပ်ပြာပုံသဏ္ဍာန်ရှိသော ဂလင်းတွင်ဖြစ်ပွားသည်။','• လည်ပင်းတွင် အလုံးအကျိတ်ပေါ်ခြင်း\n• အသံပြောင်းလဲခြင်း (အသံဝင်ခြင်း)\n• မျိုချရခက်ခဲခြင်း\n• လည်ပင်းနာကျင်ခြင်း\n• လည်ပင်းရှိ ပြန်ရည်ကျိတ်များ ရောင်ရမ်းခြင်း','ခွဲစိတ်ခြင်း၊ သိုင်းရွိုက်ဟော်မုန်းကုထုံး၊ ရေဒီယိုသတ္တိကြွ အိုင်အိုဒင်းကုထုံး၊ ပစ်မှတ်ထားကုထုံး။','https://images.unsplash.com/photo-1579684385127-1ef15d508118?auto=format&fit=crop&q=80&w=800'),
('14','mm','ကျောက်ကပ်ကင်ဆာ','ကျောက်ကပ်ကင်ဆာသည် ကျောက်ကပ်တွင် စတင်ဖြစ်ပွားသည်။ ကျောက်ကပ်များသည် ဝမ်းဗိုက်အနောက်ဘက်၊ ကျောရိုး၏ ဘေးတစ်ဖက်တစ်ချက်တွင် ရှိကြသည်။','• ဆီးထဲတွင် သွေးပါခြင်း (ပန်းရောင် သို့မဟုတ် အနီရောင်)\n• မပျောက်နိုင်သော ခါးနာခြင်း\n• အစားအသောက်ပျက်ခြင်း\n• ကိုယ်အလေးချိန်ကျခြင်း\n• မောပန်းခြင်း\n• ဖျားခြင်း','ခွဲစိတ်ခြင်း၊ အအေးပေးကုသခြင်း (Cryoablation)၊ ခုခံအားကုထုံး၊ ပစ်မှတ်ထားကုထုံး။','https://images.unsplash.com/photo-1559757175-5700dde675bc?auto=format&fit=crop&q=80&w=800'),
('15','mm','ဆီးအိမ်ကင်ဆာ','ဆီးအိမ်ကင်ဆာသည် ဆီးသိုလှောင်ရာ အင်္ဂါဖြစ်သော ဆီးအိမ်၏ အတွင်းနံရံဆဲလ်များတွင် စတင်ဖြစ်ပွားလေ့ရှိသည်။','• ဆီးထဲတွင် သွေးပါခြင်း\n• ဆီးခဏခဏသွားခြင်း\n• ဆီးသွားစဉ် နာကျင်ခြင်း\n• ခါးနာခြင်း','ခွဲစိတ်ခြင်း၊ ဆီးအိမ်တွင်း ဆေးထည့်ကုသခြင်း၊ ဆေးသွင်းကုသခြင်း၊ ဓာတ်ကင်ခြင်း၊ ခုခံအားကုထုံး။','https://images.unsplash.com/photo-1631217868264-e5b90bb7e133?auto=format&fit=crop&q=80&w=800')
INSERT INTO hospitals (id, lang, name, address, phone, description, image_url, rating, specialties) VALUES
('1','mm','ရန်ကုန်ပြည်သူ့ဆေးရုံကြီး','ဗိုလ်ချုပ်အောင်ဆန်းလမ်း၊ လမ်းမတော်မြို့နယ်၊ ရန်ကုန်မြို့။','၀၁-၂၅၆၁၁၂','ရန်ကုန်ပြည်သူ့ဆေးရုံကြီးသည် မြန်မာနိုင်ငံ၏ အဓိက ပြည်သူ့ဆေးရုံကြီးဖြစ်ပြီး ကင်ဆာကုသမှုအပါအဝင် ဘက်စုံကျန်းမာရေးစောင့်ရှောက်မှုများကို ပေးအပ်လျက်ရှိသည်။','https://images.unsplash.com/photo-1538108149393-fbbd81895907?auto=format&fit=crop&q=80&w=800',4.5,ARRAY['ကင်ဆာရောဂါ','ခွဲစိတ်ကုသမှု','အထွေထွေဆေးကုသမှု','အရေးပေါ်ကုသမှု']),
('2','mm','ပင်လုံဆေးရုံ','အမှတ် (၂၆/က)၊ ပင်လုံလမ်း၊ မြောက်ဒဂုံမြို့နယ်၊ ရန်ကုန်မြို့။','၀၁-၅၈၁၃၄၃','ပင်လုံဆေးရုံသည် မြန်မာနိုင်ငံရှိ ထိပ်တန်းပုဂ္ဂလိကဆေးရုံများထဲမှ တစ်ခုဖြစ်ပြီး ကင်ဆာကုသမှုစင်တာ၊ PET CT နှင့် ဓာတ်ရောင်ခြည်ကုသမှုတို့ဖြင့် လူသိများသည်။','https://images.unsplash.com/photo-1586773860418-d37222d8fce3?auto=format&fit=crop&q=80&w=800',4.8,ARRAY['ကင်ဆာကုသမှုဌာန','နှလုံးဌာန','ဦးနှောက်နှင့်အာရုံကြော','နျူကလီးယားဆေးပညာ']),
('3','mm','အာရှတော်ဝင်ဆေးရုံ','အမှတ် (၁၄)၊ ဗဟန်းလမ်း၊ စမ်းချောင်းမြို့နယ်၊ ရန်ကုန်မြို့။','၀၁-၅၄၄၄၆၆','အာရှတော်ဝင်ဆေးရုံသည် နိုင်ငံတကာအဆင့်မီ ကျန်းမာရေးဝန်ဆောင်မှုများကို ပေးစွမ်းနေသော ပုဂ္ဂလိကဆေးရုံကြီးဖြစ်သည်။','https://images.unsplash.com/photo-1516549655169-df83a0774514?auto=format&fit=crop&q=80&w=800',4.7,ARRAY['ကင်ဆာဌာန','ကျောက်ကပ်ဌာန','သားဖွားမီးယပ်','အထွေထွေကုသမှု']),
('4','mm','ပန်းလှိုင်စီလုံဆေးရုံ','ပန်းလှိုင်ဂေါက်ကွင်းအိမ်ရာ၊ လှိုင်သာယာမြို့နယ်၊ ရန်ကုန်မြို့။','၀၁-၆၈၄၃၂၃','ပန်းလှိုင်စီလုံဆေးရုံသည် JCI အသိအမှတ်ပြု ခေတ်မီဆေးရုံကြီးဖြစ်ပြီး နိုင်ငံတကာအဆင့်မီ ဘေးကင်းလုံခြုံမှုနှင့် ကုသမှုများကို ဝန်ဆောင်မှုပေးနေသည်။','https://images.unsplash.com/photo-1586773860418-d37222d8fce3?auto=format&fit=crop&q=80&w=800',4.9,ARRAY['ကင်ဆာကုသမှု','အရိုးအကြော','နှလုံးဌာန','အရေးပေါ်ကုသမှု']),
('5','mm','ဂရန်းဟံသာ အပြည်ပြည်ဆိုင်ရာဆေးရုံ','အမှတ် ၃၊ နတ်နတ်တောလမ်းနှင့် ကြည့်မြင်တိုင်ကမ်းနားလမ်းထောင့်၊ ကမာရွတ်မြို့နယ်၊ ရန်ကုန်မြို့။','၀၁-၅၂၃၀၀၀','ဂရန်းဟံသာ အပြည်ပြည်ဆိုင်ရာဆေးရုံသည် ရန်ကုန်မြို့တွင် တည်ရှိသော ပုဂ္ဂလိကဆေးရုံကြီးဖြစ်သည်။','https://images.unsplash.com/photo-1519494026892-80bbd2d6fd0d?auto=format&fit=crop&q=80&w=800',4.7,ARRAY['နှလုံးဌာန','ဦးနှောက်နှင့်အာရုံကြော','အစာအိမ်နှင့်အူလမ်းကြောင်း','ကင်ဆာဌာန'])
INSERT INTO blogs (id, lang, title, author, content, image_url, date, category) VALUES
('1','mm','ကင်ဆာကာကွယ်ခြင်း','ဒေါက်တာ အောင်ကျော်','ကျန်းမာရေးနှင့် ညီညွတ်သော နေထိုင်မှုပုံစံကို ရွေးချယ်ခြင်းဖြင့် ကင်ဆာဖြစ်ပွားနိုင်ခြေကို လျှော့ချနိုင်သည်။ ဆေးလိပ်ရှောင်ခြင်းသည် အရေးကြီးဆုံးဖြစ်သည်။ ကျန်းမာရေးနှင့် ညီညွတ်သော အစားအစာများကို စားသုံးခြင်း၊ ကိုယ်လက်လှုပ်ရှားမှု မှန်မှန်ပြုလုပ်ခြင်းနှင့် ကိုယ်အလေးချိန် ထိန်းသိမ်းခြင်းတို့သည်လည်း အရေးကြီးပါသည်။','https://images.unsplash.com/photo-1505751172876-fa1923c5c528?auto=format&fit=crop&q=80&w=800',NOW() - INTERVAL '2 days','ကာကွယ်ရေး'),
('2','mm','ကင်ဆာလက္ခဏာများ','ဒေါက်တာ လှမြင့်','စောစီးစွာ သိရှိခြင်းသည် ကင်ဆာကုသမှုအတွက် အလွန်အရေးကြီးသည်။ ပုံမှန်မဟုတ်သော အကျိတ်များ၊ ကိုယ်အလေးချိန် ရုတ်တရက်ကျဆင်းခြင်း၊ နာတာရှည်ချောင်းဆိုးခြင်း၊ ဝမ်းသွားခြင်း အလေ့အထပြောင်းလဲခြင်း စသည့် လက္ခဏာများကို သတိပြုပါ။','https://images.unsplash.com/photo-1576091160399-112ba8d25d1d?auto=format&fit=crop&q=80&w=800',NOW() - INTERVAL '5 days','ကျန်းမာရေး'),
('3','mm','ကုသမှုနည်းလမ်းသစ်များ','ပါမောက္ခ ဒေါက်တာစိုး','ဆေးပညာတိုးတက်လာသည်နှင့်အမျှ ကင်ဆာကုသမှုနည်းလမ်းသစ်များ ပေါ်ထွက်လာလျက်ရှိသည်။ ခုခံအားကုထုံး (Immunotherapy) နှင့် ပစ်မှတ်ထားကုသခြင်း (Targeted Therapy) တို့သည် လူနာများအတွက် မျှော်လင့်ချက်အသစ်များကို ပေးစွမ်းလျက်ရှိသည်။','https://images.unsplash.com/photo-1532187863486-abf9dbad1b69?auto=format&fit=crop&q=80&w=800',NOW() - INTERVAL '10 days','သုတေသန'),
('4','mm','စိတ်ဓာတ်ခွန်အား','ဒေါက်တာ မျိုးမင်း','ကင်ဆာရောဂါခံစားရချိန်တွင် စိတ်ဓာတ်ခွန်အားသည် အလွန်အရေးကြီးသည်။ မိသားစု၊ မိတ်ဆွေများနှင့် ဆရာဝန်များ၏ အားပေးကူညီမှုသည် ရောဂါကို ရုန်းကန်ကျော်ဖြတ်ရာတွင် များစွာအထောက်အကူပြုပါသည်။','https://images.unsplash.com/photo-1529333166437-7750a6dd5a70?auto=format&fit=crop&q=80&w=800',NOW() - INTERVAL '15 days','ပံ့ပိုးမှု'),
('5','mm','စိတ်ကျန်းမာရေး','ဒေါက်တာ ကျော်','ကင်ဆာကုသမှု ခံယူနေချိန်တွင် စိတ်ကျန်းမာရေးသည် အလွန်အရေးကြီးသည်။ တရားထိုင်ခြင်း၊ ယောဂကျင့်ခြင်းနှင့် စိတ်အပန်းဖြေနည်းများသည် စိတ်ဖိစီးမှုကို လျော့နည်းစေပြီး ပြန်လည်ကျန်းမာလာမှုကို အထောက်အကူပြုနိုင်သည်။','https://images.unsplash.com/photo-1506126613408-eca07ce68773?auto=format&fit=crop&q=80&w=800',NOW() - INTERVAL '20 days','စိတ်ကျန်းမာရေး'),
('6','mm','ပြုစုစောင့်ရှောက်သူများအတွက် လမ်းညွှန်','သူနာပြု ဆုဆု','ကင်ဆာလူနာကို ပြုစုစောင့်ရှောက်ရခြင်းသည် စိန်ခေါ်မှုများသော အလုပ်တစ်ခုဖြစ်သည်။ သင့်ကိုယ်သင် ဂရုစိုက်ရန်လည်း မမေ့ပါနှင့်။ ဤလမ်းညွှန်သည် ဆေးဝါးစီမံခန့်ခွဲမှုနှင့် စိတ်ပိုင်းဆိုင်ရာ ပံ့ပိုးမှုများအတွက် အထောက်အကူပြုမည်ဖြစ်သည်။','https://images.unsplash.com/photo-1576765608535-5f04d1e3f289?auto=format&fit=crop&q=80&w=800',NOW() - INTERVAL '25 days','ပြုစုစောင့်ရှောက်ရေး')
INSERT INTO treatments (id, lang, name, description, procedure_steps, side_effects, recovery, image_url, applicable_cancers) VALUES
('1','mm','ခွဲစိတ်ကုသခြင်း','ခွဲစိတ်ကုသခြင်းသည် ကင်ဆာအများစုအတွက် ပထမဆုံးရွေးချယ်လေ့ရှိသော ကုသမှုဖြစ်သည်။ ခန္ဓာကိုယ်မှ အကျိတ်နှင့် ဘေးပတ်ဝန်းကျင်ရှိ တစ်ရှူးများကို ဖယ်ရှားခြင်းဖြစ်သည်။','ကင်ဆာအမျိုးအစားနှင့် တည်နေရာအပေါ်မူတည်၍ ခွဲစိတ်မှုပုံစံ ကွာခြားနိုင်သည်။\n• အကျိတ်နှင့် ကျန်းမာသောတစ်ရှူးအချို့ကို ဖယ်ရှားခြင်း\n• နီးစပ်ရာ ပြန်ရည်ကျိတ်များကို ဖယ်ရှားခြင်း\n• လိုအပ်ပါက ပြန်လည်ပြုပြင်ခြင်း ခွဲစိတ်မှုများ ပြုလုပ်ခြင်း\n• အနည်းဆုံး ထိခိုက်မှုရှိသော ခွဲစိတ်နည်းများ','• ခွဲစိတ်ဒဏ်ရာ နာကျင်ခြင်း\n• ပိုးဝင်ခြင်း\n• သွေးထွက်ခြင်း\n• မောပန်းနွမ်းနယ်ခြင်း\n• အမာရွတ်ကျန်ခြင်း','ခွဲစိတ်မှုပမာဏအပေါ်မူတည်၍ ပြန်လည်သက်သာရန် ရက်သတ္တပတ်အနည်းငယ်မှ လအနည်းငယ်အထိ ကြာနိုင်သည်။','https://images.unsplash.com/photo-1551190822-a9333d879b1f?auto=format&fit=crop&q=80&w=800',ARRAY['ရင်သားကင်ဆာ','အဆုတ်ကင်ဆာ','အူမကြီးကင်ဆာ','အရေပြားကင်ဆာ','သားဥအိမ်ကင်ဆာ','သိုင်းရွိုက်ကင်ဆာ']),
('2','mm','ဆေးသွင်းကုသခြင်း','ဆေးသွင်းကုသခြင်း (Chemotherapy) သည် ကင်ဆာဆဲလ်များကို သတ်ရန် သို့မဟုတ် ကြီးထွားမှုကို တားဆီးရန် အားပြင်းသောဆေးဝါးများကို အသုံးပြုခြင်းဖြစ်သည်။','ပေးနိုင်သော ပုံစံများ:\n• သွေးကြောမှတစ်ဆင့် သွင်းခြင်း (IV)\n• သောက်ဆေးအဖြစ် သောက်ခြင်း\n• ထိုးဆေးအဖြစ် အသုံးပြုခြင်း\n• လိမ်းဆေးအဖြစ် အသုံးပြုခြင်း\n• စက်ဝန်းပုံစံဖြင့် ကုသခြင်း','• ဆံပင်ကျွတ်ခြင်း\n• ပျို့အန်ခြင်း\n• မောပန်းခြင်း\n• ပိုးဝင်လွယ်ခြင်း\n• အစားအသောက်ပျက်ခြင်း\n• ပါးစပ်အနာဖြစ်ခြင်း\n• အရသာပျက်ခြင်း','ကုသမှုပြီးဆုံးပြီးနောက် ဘေးထွက်ဆိုးကျိုးများ သက်သာလာလေ့ရှိသည်။ ဆံပင်သည် ၃-၆ လအတွင်း ပြန်လည်ပေါက်ရောက်နိုင်သည်။','https://images.unsplash.com/photo-1579154204601-01588f351e67?auto=format&fit=crop&q=80&w=800',ARRAY['သွေးကင်ဆာ','ပြန်ရည်ကျိတ်ကင်ဆာ','ရင်သားကင်ဆာ','အဆုတ်ကင်ဆာ','သားဥအိမ်ကင်ဆာ','ဆီးအိမ်ကင်ဆာ']),
('3','mm','ဓာတ်ကင်ခြင်း','ဓာတ်ကင်ခြင်း (Radiation Therapy) သည် စွမ်းအားမြင့် ရောင်ခြည်များကို အသုံးပြု၍ ကင်ဆာဆဲလ်များကို ဖျက်ဆီးခြင်းဖြစ်သည်။','• ကုသမည့်နေရာကို CT scan ရိုက်၍ ပုံဖော်ခြင်း\n• နေ့စဉ် ကုသမှုခံယူရခြင်း (များသောအားဖြင့် တစ်ပတ် ၅ ရက်)\n• တစ်ကြိမ်လျှင် ၁၀-၃၀ မိနစ် ကြာမြင့်ခြင်း\n• နာကျင်မှုမရှိခြင်း','• အရေပြားနီခြင်း၊ ခြောက်သွေ့ခြင်း\n• မောပန်းခြင်း\n• ကုသသောနေရာတွင် အမွေးအမျှင်ကျွတ်ခြင်း\n• ပျို့အန်ခြင်း (ဝမ်းဗိုက်ပိုင်းဖြစ်ပါက)\n• မျိုချရခက်ခဲခြင်း (လည်ပင်းပိုင်းဖြစ်ပါက)','ကုသမှုပြီးဆုံးပြီး ရက်သတ္တပတ်အနည်းငယ်အတွင်း ဘေးထွက်ဆိုးကျိုးများ သက်သာလာလေ့ရှိသည်။','https://images.unsplash.com/photo-1516549655169-df83a0774514?auto=format&fit=crop&q=80&w=800',ARRAY['ရင်သားကင်ဆာ','အဆုတ်ကင်ဆာ','ဆီးကျိတ်ကင်ဆာ','ဦးနှောက်အကျိတ်','သားအိမ်ခေါင်းကင်ဆာ']),
('4','mm','ခုခံအားကုထုံး','ခုခံအားကုထုံး (Immunotherapy) သည် ခန္ဓာကိုယ်၏ ခုခံအားစနစ်ကို အသုံးပြု၍ ကင်ဆာကို တိုက်ခိုက်ခြင်းဖြစ်သည်။','• သွေးကြောမှတစ်ဆင့် သွင်းခြင်း (IV)\n• သောက်ဆေးများ\n• လိမ်းဆေးများ\n• ဆီးအိမ်အတွင်းသို့ တိုက်ရိုက်ထည့်ခြင်း','• တုပ်ကွေးကဲ့သို့ လက္ခဏာများ (ဖျားခြင်း၊ ချမ်းခြင်း)\n• မောပန်းခြင်း\n• အရေပြားယားယံခြင်း\n• ဝမ်းလျှောခြင်း\n• ကိုယ်အလေးချိန် အပြောင်းအလဲ','ကုသမှုပြီးဆုံးပြီးနောက်တွင်လည်း ဆက်လက်၍ အာနိသင်ရှိနိုင်သည်။ ပုံမှန်စစ်ဆေးမှုများ ပြုလုပ်ရန် လိုအပ်သည်။','https://images.unsplash.com/photo-1582719471137-c3967ffb1c42?auto=format&fit=crop&q=80&w=800',ARRAY['အရေပြားကင်ဆာ (Melanoma)','အဆုတ်ကင်ဆာ','ကျောက်ကပ်ကင်ဆာ','ဆီးအိမ်ကင်ဆာ','ပြန်ရည်ကျိတ်ကင်ဆာ']),
('5','mm','ပစ်မှတ်ထားကုထုံး','ပစ်မှတ်ထားကုထုံး (Targeted Therapy) သည် ကင်ဆာဆဲလ်များ ကြီးထွားမှုကို အားပေးသော မျိုးရိုးဗီဇ သို့မဟုတ် ပရိုတင်းများကို တိုက်ခိုက်ခြင်းဖြစ်သည်။','• သောက်ဆေးများ (ဆေးပြား သို့မဟုတ် ဆေးတောင့်)\n• သွေးကြောမှတစ်ဆင့် သွင်းခြင်း\n• အရေပြားအောက် ထိုးဆေးများ\n• အခြားကုထုံးများနှင့် တွဲဖက်အသုံးပြုတတ်သည်','• ဝမ်းလျှောခြင်း\n• အသည်းပြဿနာများ\n• အရေပြားပြောင်းလဲမှုများ\n• သွေးပေါင်ချိန်တက်ခြင်း\n• သွေးခဲခြင်းပြဿနာများ\n• အနာကျက်နှေးခြင်း','ဘေးထွက်ဆိုးကျိုးများသည် ဆေးသွင်းကုသခြင်းလောက် မပြင်းထန်တတ်ပါ။ ကုသမှုရပ်လိုက်ပါက သက်သာလာလေ့ရှိသည်။','https://images.unsplash.com/photo-1576091160550-2173dba999ef?auto=format&fit=crop&q=80&w=800',ARRAY['ရင်သားကင်ဆာ','အဆုတ်ကင်ဆာ','အူမကြီးကင်ဆာ','သွေးကင်ဆာ','အရေပြားကင်ဆာ','ကျောက်ကပ်ကင်ဆာ','သိုင်းရွိုက်ကင်ဆာ']),
('6','mm','ဟော်မုန်းကုထုံး','ဟော်မုန်းကုထုံး (Hormone Therapy) သည် ဟော်မုန်းကိုအသုံးပြု၍ ကြီးထွားသော ကင်ဆာများကို ကုသရာတွင် အသုံးပြုသည်။','• နေ့စဉ်သောက်ဆေးများ\n• ထိုးဆေးများ (လစဉ် သို့မဟုတ် လအနည်းငယ်ကြာတစ်ကြိမ်)\n• ဟော်မုန်းထုတ်သော အင်္ဂါကို ခွဲစိတ်ဖယ်ရှားခြင်း\n• ၅ နှစ်မှ ၁၀ နှစ်အထိ ကြာမြင့်နိုင်သည်','• ပူရှိန်းရှိန်းဖြစ်ခြင်း\n• မောပန်းခြင်း\n• စိတ်အပြောင်းအလဲမြန်ခြင်း\n• အရိုးပွခြင်း\n• ကိုယ်အလေးချိန်တက်ခြင်း\n• အဆစ်အမြစ်နာခြင်း','ကုသမှုပြီးဆုံးပါက ဘေးထွက်ဆိုးကျိုးများ သက်သာလေ့ရှိသည်။ ရေရှည်အကျိုးကျေးဇူးသည် ယာယီဆိုးကျိုးများထက် ပိုမိုများပြားသည်။','https://images.unsplash.com/photo-1587854692152-cbe660dbde88?auto=format&fit=crop&q=80&w=800',ARRAY['ရင်သားကင်ဆာ','ဆီးကျိတ်ကင်ဆာ','သားဥအိမ်ကင်ဆာ','သားအိမ်ကင်ဆာ','သိုင်းရွိုက်ကင်ဆာ'])
